<template>
  <AppLayout>
    <div class="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div class="mb-8">
        <router-link
          to="/transactions"
          class="inline-flex items-center gap-2 text-indigo-600 transition hover:text-indigo-900"
        >
          ← Back to Transactions
        </router-link>
      </div>

      <div v-if="isLoading" class="flex justify-center py-16">
        <div class="h-12 w-12 animate-spin rounded-full border-b-2 border-indigo-600"></div>
      </div>

      <div
        v-else-if="error"
        class="rounded-2xl border border-red-200 bg-red-50 px-4 py-4 text-red-700"
      >
        <div class="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <p class="font-semibold">Unable to load transaction</p>
            <p class="mt-1 text-sm text-red-600">{{ error }}</p>
          </div>
          <button
            type="button"
            class="inline-flex items-center justify-center rounded-lg bg-red-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-red-700"
            @click="fetchTransaction"
          >
            Retry
          </button>
        </div>
      </div>

      <div v-else-if="transaction" class="space-y-6">
        <section class="rounded-2xl bg-white p-6 shadow-sm ring-1 ring-gray-200">
          <div class="flex flex-col gap-6 lg:flex-row lg:items-start lg:justify-between">
            <div class="space-y-3">
              <div class="inline-flex items-center rounded-full bg-indigo-50 px-3 py-1 text-xs font-semibold uppercase tracking-[0.2em] text-indigo-700">
                Transaction {{ shortTransactionId }}
              </div>
              <div>
                <h1 class="text-3xl font-bold text-gray-900">Transaction Details</h1>
                <p class="mt-2 text-sm text-gray-600">
                  Payment intent {{ transaction.paymentIntentId }}
                </p>
              </div>
            </div>

            <div
              :class="[
                'inline-flex items-center rounded-full px-4 py-2 text-sm font-semibold',
                statusBadgeClasses(transaction.status),
              ]"
            >
              {{ transaction.status }}
            </div>
          </div>

          <div class="mt-6 grid gap-4 md:grid-cols-3">
            <div class="rounded-xl bg-slate-50 p-4">
              <p class="text-xs font-semibold uppercase tracking-wide text-slate-500">Amount</p>
              <p class="mt-2 text-2xl font-bold text-gray-900">
                {{ transaction.currency }} {{ transaction.amount.toFixed(2) }}
              </p>
            </div>
            <div class="rounded-xl bg-slate-50 p-4">
              <p class="text-xs font-semibold uppercase tracking-wide text-slate-500">Created at</p>
              <p class="mt-2 text-base font-semibold text-gray-900">
                {{ formatDateTime(transaction.createdAt) }}
              </p>
            </div>
            <div class="rounded-xl bg-slate-50 p-4">
              <p class="text-xs font-semibold uppercase tracking-wide text-slate-500">Last updated</p>
              <p class="mt-2 text-base font-semibold text-gray-900">
                {{ formatDateTime(transaction.updatedAt) }}
              </p>
            </div>
          </div>
        </section>

        <div class="grid gap-6 lg:grid-cols-[minmax(0,1.8fr)_minmax(320px,1fr)]">
          <section class="space-y-6">
            <div class="rounded-2xl bg-white p-6 shadow-sm ring-1 ring-gray-200">
              <h2 class="text-xl font-semibold text-gray-900">Payment Information</h2>
              <p class="mt-2 text-sm text-gray-600">
                Details associated with the payment intent and transaction processing.
              </p>

              <div class="mt-6 grid gap-4 sm:grid-cols-2">
                <div class="rounded-xl border border-gray-200 p-4">
                  <p class="text-xs font-semibold uppercase tracking-wide text-gray-500">Transaction ID</p>
                  <p class="mt-2 break-all font-mono text-sm text-gray-900">{{ transaction.id }}</p>
                </div>
                <div class="rounded-xl border border-gray-200 p-4">
                  <p class="text-xs font-semibold uppercase tracking-wide text-gray-500">Payment Intent ID</p>
                  <p class="mt-2 break-all font-mono text-sm text-gray-900">
                    {{ transaction.paymentIntentId }}
                  </p>
                </div>
                <div class="rounded-xl border border-gray-200 p-4">
                  <p class="text-xs font-semibold uppercase tracking-wide text-gray-500">Status</p>
                  <p class="mt-2 text-sm font-semibold text-gray-900">{{ transaction.status }}</p>
                </div>
                <div v-if="transaction.paymentMethod" class="rounded-xl border border-gray-200 p-4">
                  <p class="text-xs font-semibold uppercase tracking-wide text-gray-500">Payment Method</p>
                  <p class="mt-2 text-sm font-semibold text-gray-900">{{ transaction.paymentMethod }}</p>
                </div>
              </div>
            </div>

            <div class="rounded-2xl bg-white p-6 shadow-sm ring-1 ring-gray-200">
              <h2 class="text-xl font-semibold text-gray-900">Lifecycle</h2>
              <div class="mt-4 rounded-xl bg-slate-50 p-4 text-sm text-slate-700">
                <p class="font-semibold text-slate-900">{{ transactionStatusTitle }}</p>
                <p class="mt-2">{{ transactionStatusDescription }}</p>
              </div>
            </div>
          </section>

          <aside class="space-y-6">
            <div class="rounded-2xl bg-white p-6 shadow-sm ring-1 ring-gray-200">
              <h2 class="text-xl font-semibold text-gray-900">Refunds</h2>
              <p class="mt-2 text-sm text-gray-600">
                Refunds can be processed only for succeeded transactions.
              </p>

              <div v-if="transaction.status === 'SUCCEEDED'" class="mt-6 space-y-4">
                <div class="rounded-xl border border-emerald-200 bg-emerald-50 p-4 text-sm text-emerald-900">
                  <p class="font-semibold">Refund enabled</p>
                  <p class="mt-1 text-emerald-800">
                    You can create a full or partial refund for {{ transaction.currency }}
                    {{ transaction.amount.toFixed(2) }}.
                  </p>
                </div>

                <button
                  type="button"
                  class="inline-flex w-full items-center justify-center rounded-lg bg-indigo-600 px-4 py-3 font-semibold text-white transition hover:bg-indigo-700"
                  @click="openRefundDialog"
                >
                  Process Refund
                </button>
              </div>

              <div v-else class="mt-6 rounded-xl border border-dashed border-gray-300 bg-gray-50 p-4 text-sm text-gray-600">
                <p class="font-semibold text-gray-900">Refund unavailable</p>
                <p class="mt-1">
                  This transaction must be in <span class="font-semibold">SUCCEEDED</span> state before a refund can be created.
                </p>
              </div>
            </div>

            <div v-if="lastRefund" class="rounded-2xl bg-white p-6 shadow-sm ring-1 ring-gray-200">
              <h2 class="text-xl font-semibold text-gray-900">Last Refund</h2>
              <div class="mt-4 rounded-xl bg-slate-50 p-4 text-sm text-slate-700">
                <p class="font-semibold text-slate-900">{{ lastRefund.status }}</p>
                <p class="mt-1">
                  {{ lastRefund.transactionId }}
                </p>
                <p class="mt-3 text-lg font-semibold text-gray-900">
                  {{ transaction.currency }} {{ lastRefund.amount.toFixed(2) }}
                </p>
                <p class="mt-1 text-slate-600">{{ lastRefund.reason }}</p>
              </div>
            </div>
          </aside>
        </div>
      </div>
    </div>

    <RefundDialog
      v-model="showRefundDialog"
      :currency="transaction?.currency || ''"
      :transaction-amount="transaction?.amount || 0"
      :processing="isProcessingRefund"
      :server-error="refundError"
      @confirm="handleRefund"
    />
  </AppLayout>
</template>

<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import { useRoute } from 'vue-router'
import AppLayout from '@/layouts/AppLayout.vue'
import RefundDialog from '@/components/shared/RefundDialog.vue'
import { transactionService } from '@/services/transactions'
import { useNotificationStore } from '@/stores/notifications'
import type { Refund, Transaction } from '@/types'

const route = useRoute()
const notificationStore = useNotificationStore()

const transaction = ref<Transaction | null>(null)
const isLoading = ref(false)
const error = ref('')

const showRefundDialog = ref(false)
const isProcessingRefund = ref(false)
const refundError = ref<string | null>(null)
const lastRefund = ref<Refund | null>(null)

const shortTransactionId = computed(() => transaction.value?.id.slice(0, 8) ?? '')
const transactionStatusTitle = computed(() => {
  switch (transaction.value?.status) {
    case 'SUCCEEDED':
      return 'Payment completed successfully'
    case 'PENDING':
      return 'Payment is still being processed'
    case 'FAILED':
      return 'Payment failed'
    case 'CANCELED':
      return 'Payment was canceled'
    case 'REFUNDED':
      return 'Payment has been refunded'
    default:
      return 'Unknown payment state'
  }
})
const transactionStatusDescription = computed(() => {
  switch (transaction.value?.status) {
    case 'SUCCEEDED':
      return 'You can open the refund modal to create a full or partial refund for this transaction.'
    case 'PENDING':
      return 'Wait until the transaction settles before refunding it.'
    case 'FAILED':
      return 'Failed transactions cannot be refunded because no payment was captured.'
    case 'CANCELED':
      return 'Canceled transactions are not eligible for refunds.'
    case 'REFUNDED':
      return 'The transaction has already been refunded and no further refund action should be needed.'
    default:
      return 'Transaction status information is unavailable.'
  }
})

async function fetchTransaction() {
  isLoading.value = true
  error.value = ''

  try {
    transaction.value = await transactionService.getById(route.params.id as string)
  } catch (err: any) {
    transaction.value = null
    error.value = err.response?.data?.message || 'Failed to load transaction'
  } finally {
    isLoading.value = false
  }
}

function statusBadgeClasses(status: Transaction['status']) {
  switch (status) {
    case 'SUCCEEDED':
      return 'bg-emerald-100 text-emerald-800'
    case 'PENDING':
      return 'bg-amber-100 text-amber-800'
    case 'FAILED':
      return 'bg-red-100 text-red-800'
    case 'CANCELED':
      return 'bg-slate-100 text-slate-700'
    case 'REFUNDED':
      return 'bg-indigo-100 text-indigo-800'
    default:
      return 'bg-gray-100 text-gray-800'
  }
}

function formatDateTime(value?: string | Date | null) {
  if (!value) {
    return 'N/A'
  }

  const date = new Date(value)

  if (Number.isNaN(date.getTime())) {
    return 'N/A'
  }

  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
  }).format(date)
}

function openRefundDialog() {
  if (!transaction.value || transaction.value.status !== 'SUCCEEDED') {
    return
  }

  refundError.value = null
  showRefundDialog.value = true
}

function handleRefund(payload: { amount: number; reason: string }) {
  if (!transaction.value) {
    return
  }

  isProcessingRefund.value = true
  refundError.value = null

  transactionService
    .refund(transaction.value.id, payload.amount, payload.reason)
    .then((createdRefund) => {
      lastRefund.value = createdRefund
      notificationStore.success(
        `Refund request submitted for ${transaction.value?.currency} ${payload.amount.toFixed(2)}`
      )
      showRefundDialog.value = false
      return fetchTransaction()
    })
    .catch((err: any) => {
      refundError.value = err.response?.data?.message || 'Failed to process refund'
      notificationStore.error('Failed to process refund')
    })
    .finally(() => {
      isProcessingRefund.value = false
    })
}

onMounted(() => {
  fetchTransaction()
})
</script>

